from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
CLASS_DIR = ROOT / "Rankings" / "吟游诗人"
RECORD = ROOT / "Rankings" / "changelog.md"

ASPECTS = ["近战伤害者", "远程伤害者", "法术伤害者", "防御和生存", "治疗和临时生命", "团队增益", "反制施法者", "减益", "战场分隔", "召唤 / 伙伴", "技能使用", "制造"]
TIERS = ["Tier 1（1-4）", "Tier 2（5-10）", "Tier 3（11-16）", "Tier 4（17-20）"]


def table(rows):
    out = ["| 项目 | Tier 1（1-4） | Tier 2（5-10） | Tier 3（11-16） | Tier 4（17-20） |", "|---|---|---|---|---|"]
    for name, vals in rows:
        out.append(f"| {name} | {' | '.join(vals)} |")
    return "\n".join(out)


def overall(rows):
    out = ["## 综合评分", "| 阶段 | 综合强度 | 具体理由 |", "|---|---|---|"]
    for tier, rank, reason in rows:
        out.append(f"| {tier} | {rank} | {reason} |")
    return "\n".join(out)


def design(rows):
    out = ["## 设计相关评分", "| 项目 | 评分 | 具体理由 |", "|---|---|---|"]
    for name, rank, reason in rows:
        out.append(f"| {name} | {rank} | {reason} |")
    return "\n".join(out)


def write(name, body):
    path = CLASS_DIR / name
    path.write_text(body.strip() + "\n", encoding="utf-8")


def subclass_doc(name, source, role, detail, aspect_rows, overall_rows, design_rows):
    return f"""# {name}

## 来源与版本

- 本轮依据：{source}
- 兼容口径：旧 5e / 2014 子职并入 2024 吟游诗人底盘时，低于 3 级的子职能力按 3 级进入；同名新版官方子职优先使用 2024 文本，UA 改写另列 `（UA）`。

## 队伍定位调整

{role}

## 详细评价

{detail}

## 分项评分
{table(aspect_rows)}

{overall(overall_rows)}

{design(design_rows)}
"""


